import{a as e,c as t,d as n,f as r,u as i,w as a,x as o,y as s}from"./runtime-core.esm-bundler-CD3o_SA6.js";import{t as c}from"./_plugin-vue_export-helper-B80Cc4Ui.js";var l={},u={class:`chapter-header`},d={class:`breadcrumb`},f={class:`page-container`},p={class:`chapter-nav`};function m(c,l){let m=o(`router-link`);return s(),t(`div`,null,[e(`header`,u,[e(`div`,d,[r(m,{to:`/`},{default:a(()=>[...l[0]||=[n(`Study Guide`,-1)]]),_:1}),l[3]||=n(` › `,-1),r(m,{to:`/sa`},{default:a(()=>[...l[1]||=[n(`SA`,-1)]]),_:1}),l[4]||=n(` › `,-1),r(m,{to:`/sa/microservices`},{default:a(()=>[...l[2]||=[n(`Microservices`,-1)]]),_:1}),l[5]||=n(` › Chapter 4`,-1)]),l[6]||=i(`<h1>Chapter 4: Managing Transactions with Sagas</h1><p class="chapter-desc">How to maintain data consistency across services without distributed transactions — using the Saga pattern, choreography vs. orchestration, and countermeasures for isolation anomalies.</p><div class="stats-bar"><span class="stat-badge">9 Patterns</span><span class="stat-badge">10 Definitions</span><span class="stat-badge">4 Principles</span><span class="stat-badge">6 Problems</span><span class="stat-badge">2 Tradeoffs</span><span class="stat-badge">2 Technologies</span><span class="stat-badge">33 Total Concepts</span></div>`,3)]),e(`div`,f,[l[9]||=i(`<nav class="toc"><h2>Table of Contents</h2><ol><li class="toc-section"><a href="#s4-1">4.1 Transaction Management in a Microservice Architecture</a><ol><li><a href="#s4-1-1">The Need for Distributed Transactions</a></li><li><a href="#s4-1-2">The Trouble with Distributed Transactions</a></li><li><a href="#s4-1-3">Using the Saga Pattern to Maintain Data Consistency</a></li></ol></li><li class="toc-section"><a href="#s4-2">4.2 Coordinating Sagas</a><ol><li><a href="#s4-2-1">Choreography-Based Sagas</a></li><li><a href="#s4-2-2">Orchestration-Based Sagas</a></li></ol></li><li class="toc-section"><a href="#s4-3">4.3 Handling the Lack of Isolation</a><ol><li><a href="#s4-3-1">Overview of Anomalies</a></li><li><a href="#s4-3-2">Countermeasures for Handling the Lack of Isolation</a></li></ol></li><li class="toc-section"><a href="#s4-4">4.4 The Design of the Order Service and the Create Order Saga</a><ol><li><a href="#s4-4-1">The OrderService Class</a></li><li><a href="#s4-4-2">The Implementation of the Create Order Saga</a></li><li><a href="#s4-4-3">The OrderCommandHandlers Class</a></li><li><a href="#s4-4-4">The OrderServiceConfiguration Class</a></li></ol></li></ol></nav><h2 class="section-title" id="s4-1">4.1 Transaction Management in a Microservice Architecture</h2><div class="content-section"><p>In a monolith, you can use a single ACID database transaction to keep data consistent. In a microservice architecture, each service has its own database. When an operation spans multiple services, you need a different approach to maintain consistency.</p></div><h3 class="subsection-title" id="s4-1-1">The Need for Distributed Transactions</h3><div class="content-section"><p>Many business operations touch data owned by more than one service. For example, creating an order in the FTGO application requires verifying the consumer, validating the restaurant menu, authorizing the credit card, and creating a kitchen ticket. Each of these actions belongs to a different service with its own database.</p><p>In a monolith, all this data lives in one database, so a single transaction guarantees consistency. In a microservice architecture, there is no single database. You cannot wrap all these steps in one ACID transaction. You need a mechanism that coordinates updates across multiple service databases.</p><div class="info-box analogy-box"><p><strong>Analogy:</strong> Imagine a group project where each team member keeps their own notebook. There is no shared notebook. If the project needs changes across all notebooks at once, the team needs a protocol to make sure everyone updates their notebook correctly — or rolls back if something goes wrong.</p></div></div><h3 class="subsection-title" id="s4-1-2">The Trouble with Distributed Transactions</h3><div class="content-section"><p>The traditional solution for cross-database consistency is <strong>distributed transactions</strong>, typically using the X/Open XA standard and two-phase commit (2PC). However, this approach has serious problems in a microservice architecture:</p><ul><li><strong>Many modern technologies do not support it</strong> — NoSQL databases (MongoDB, Cassandra) and message brokers (Apache Kafka) do not participate in XA transactions.</li><li><strong>It reduces availability</strong> — all participants must be available for the transaction to commit. The overall availability is the product of each participant&#39;s availability, which drops quickly as you add more services.</li><li><strong>CAP theorem</strong> — in a distributed system, you must choose between consistency and availability. Modern architectures favor availability over strict consistency.</li></ul><div class="info-box warning-box"><p><strong>Problem:</strong> Distributed transactions (2PC) require all participants to be available simultaneously. This reduces system availability and does not work with many modern databases and brokers. They are not a viable solution for microservices.</p></div><div class="info-box key-point-box"><p><strong>Conclusion:</strong> The failure of distributed transactions in microservices motivates the need for a different pattern — the Saga pattern.</p></div></div><h3 class="subsection-title" id="s4-1-3">Using the Saga Pattern to Maintain Data Consistency</h3><div class="content-section"><p>A <strong>saga</strong> is a sequence of local transactions. Each local transaction updates a single service&#39;s database using standard ACID guarantees, and then publishes a message or event to trigger the next step. If any step fails, the saga executes <strong>compensating transactions</strong> in reverse order to undo the work done by previous steps.</p><div class="pattern-summary"><h4>Pattern: Saga</h4><div class="ps-row"><span class="ps-label">Problem</span> <span>How to maintain data consistency across services without distributed transactions?</span></div><div class="ps-row"><span class="ps-label">Solution</span> <span>Define a saga — a sequence of local transactions coordinated via asynchronous messaging. On failure, compensating transactions undo completed steps in reverse order.</span></div><div class="ps-row"><span class="ps-label">Properties</span> <span>ACD (Atomicity, Consistency, Durability) but NO Isolation.</span></div><div class="ps-row"><span class="ps-label">Requires</span> <span>Transactional Messaging (Ch. 3) to atomically update the database and send messages.</span></div></div><h4 class="subsubsection-title">Saga Properties: ACD without Isolation</h4><p>A saga provides three of the four ACID properties:</p><ul><li><strong>Atomicity</strong> — either all local transactions execute, or all compensating transactions run to undo the work.</li><li><strong>Consistency</strong> — each local transaction preserves consistency within its service. Cross-service consistency is maintained through the saga protocol.</li><li><strong>Durability</strong> — each local transaction commits to its service&#39;s database, which provides durability.</li></ul><p>A saga does <strong>not</strong> provide <strong>isolation</strong>. Other transactions can see intermediate data while the saga is in progress. This lack of isolation can cause anomalies, which are addressed in section 4.3.</p><h4 class="subsubsection-title">Transaction Types in a Saga</h4><p>The steps of a saga fall into three categories:</p><table class="comparison-table"><thead><tr><th>Type</th><th>Description</th><th>Compensation</th></tr></thead><tbody><tr><td><strong>Compensatable</strong></td><td>Steps that can be undone. They precede the pivot transaction.</td><td>Yes — has a compensating transaction</td></tr><tr><td><strong>Pivot</strong></td><td>The go/no-go decision point. If it commits, the saga will run to completion.</td><td>No — it is the boundary</td></tr><tr><td><strong>Retriable</strong></td><td>Steps that follow the pivot. They are guaranteed to succeed.</td><td>No — always succeeds</td></tr></tbody></table><h4 class="subsubsection-title">Example: Create Order Saga</h4><p>The Create Order Saga in FTGO has six steps:</p><ol><li><strong>Order Service</strong> — create order in PENDING state <em>(compensatable)</em></li><li><strong>Consumer Service</strong> — verify consumer <em>(compensatable)</em></li><li><strong>Kitchen Service</strong> — create ticket <em>(compensatable)</em></li><li><strong>Accounting Service</strong> — authorize credit card <em>(pivot)</em></li><li><strong>Kitchen Service</strong> — approve ticket <em>(retriable)</em></li><li><strong>Order Service</strong> — approve order <em>(retriable)</em></li></ol><p>Steps 1–3 are compensatable — each has a compensating transaction that undoes its work. Step 4 is the pivot — if the credit card is authorized, the saga will definitely complete. Steps 5–6 are retriable — they are guaranteed to succeed because the pivot already committed.</p><div class="info-box analogy-box"><p><strong>Analogy:</strong> Think of booking a vacation. You reserve a flight, then a hotel, then a rental car. If the rental car is not available, you cancel the hotel and the flight in reverse order. The &quot;credit card charge&quot; step is the point of no return — once you pay, the rest of the trip will happen.</p></div></div><h2 class="section-title" id="s4-2">4.2 Coordinating Sagas</h2><div class="content-section"><p>A saga involves multiple services that must execute their steps in the right order. There are two approaches to coordinate a saga: <strong>choreography</strong> and <strong>orchestration</strong>.</p><table class="comparison-table"><thead><tr><th>Aspect</th><th>Choreography</th><th>Orchestration</th></tr></thead><tbody><tr><td>Coordination</td><td>Distributed — participants exchange events</td><td>Centralized — orchestrator sends commands</td></tr><tr><td>Coupling</td><td>Loose (via events)</td><td>Low (orchestrator knows the flow)</td></tr><tr><td>Complexity</td><td>Hard to understand as saga grows</td><td>Clear, linear flow</td></tr><tr><td>Dependencies</td><td>Risk of cyclic dependencies</td><td>No cyclic dependencies</td></tr><tr><td>Separation of concerns</td><td>Saga logic spread across participants</td><td>Saga logic centralized in orchestrator</td></tr><tr><td>Risk</td><td>Tight coupling through event chains</td><td>Bloated orchestrator with too much logic</td></tr></tbody></table><div class="info-box key-point-box"><p><strong>Recommendation:</strong> Use orchestration for all but the simplest sagas. Keep the orchestrator focused only on sequencing — it should not contain business logic.</p></div><div class="info-box note-box"><p><strong>Important:</strong> Both choreography and orchestration require <strong>Transactional Messaging</strong> (covered in Ch. 3) to atomically update the database and send/publish messages in the same operation.</p></div></div><h3 class="subsection-title" id="s4-2-1">Choreography-Based Sagas</h3><div class="content-section"><p>In a choreography-based saga, there is no central coordinator. Each participant listens for events from other participants and decides what to do next. When a participant completes its local transaction, it publishes an event. Other participants subscribe to that event and react.</p><h4 class="subsubsection-title">How It Works</h4><ol><li>Order Service creates an order and publishes an <em>OrderCreated</em> event.</li><li>Consumer Service hears the event, verifies the consumer, and publishes a <em>ConsumerVerified</em> event.</li><li>Kitchen Service hears the event, creates a ticket, and publishes a <em>TicketCreated</em> event.</li><li>And so on — each step is triggered by the previous step&#39;s event.</li></ol><h4 class="subsubsection-title">Benefits</h4><ul><li><strong>Simple</strong> — no extra orchestrator service needed</li><li><strong>Loose coupling</strong> — participants only know about events, not about each other</li></ul><h4 class="subsubsection-title">Drawbacks</h4><ul><li><strong>Hard to understand</strong> — the saga logic is spread across all participants. There is no single place to see the full flow.</li><li><strong>Cyclic dependencies</strong> — participants may subscribe to each other&#39;s events, creating dependency cycles.</li><li><strong>Risk of tight coupling</strong> — participants may need to know about events from many other services, which creates implicit coupling.</li></ul><div class="info-box analogy-box"><p><strong>Analogy:</strong> Choreography is like a dance where every dancer watches the others and decides their next move based on what they see. It works for a small group, but with many dancers it becomes chaotic because nobody has the full picture.</p></div></div><h3 class="subsection-title" id="s4-2-2">Orchestration-Based Sagas</h3><div class="content-section"><p>In an orchestration-based saga, a central <strong>orchestrator</strong> object controls the saga. The orchestrator sends command messages to participants and receives reply messages. Based on each reply, it decides what command to send next.</p><h4 class="subsubsection-title">How It Works</h4><ol><li>The orchestrator sends a command to the first participant (e.g., &quot;verify consumer&quot;).</li><li>The participant processes the command and sends a reply (success or failure).</li><li>The orchestrator receives the reply and sends the next command (e.g., &quot;create ticket&quot;).</li><li>If any step fails, the orchestrator sends compensating commands in reverse order.</li></ol><h4 class="subsubsection-title">Modeling as a State Machine</h4><p>An orchestration-based saga is naturally modeled as a <strong>state machine</strong>. It has:</p><ul><li><strong>States</strong> — represent where the saga is in its sequence (e.g., VerifyingConsumer, CreatingTicket, AuthorizingCard)</li><li><strong>Transitions</strong> — triggered by reply messages from participants</li><li><strong>Actions</strong> — commands sent to participants when entering a new state</li></ul><p>The state machine makes the saga easy to understand, test, and debug because the entire flow is visible in one place.</p><h4 class="subsubsection-title">Benefits</h4><ul><li><strong>Clear flow</strong> — the entire saga logic is in one place (the orchestrator)</li><li><strong>No cyclic dependencies</strong> — participants do not depend on each other, only the orchestrator depends on participants</li><li><strong>Better separation of concerns</strong> — participants only need to implement the command they receive; they do not need to know about the saga</li></ul><h4 class="subsubsection-title">Drawbacks</h4><ul><li><strong>Risk of bloated orchestrator</strong> — if you put too much business logic in the orchestrator, it becomes a &quot;god class.&quot; Keep it focused on sequencing only.</li></ul><div class="info-box analogy-box"><p><strong>Analogy:</strong> Orchestration is like a conductor leading an orchestra. The conductor tells each section when to play and what to play. Each musician focuses on their own part. The conductor keeps everyone in sync and handles the overall flow.</p></div></div><h2 class="section-title" id="s4-3">4.3 Handling the Lack of Isolation</h2><div class="content-section"><p>Unlike ACID transactions, sagas do not provide isolation. While a saga is running, other transactions can read and modify the same data. This can cause anomalies. This section describes the anomalies and the countermeasures to handle them.</p></div><h3 class="subsection-title" id="s4-3-1">Overview of Anomalies</h3><div class="content-section"><p>The lack of isolation can cause three types of anomalies:</p><table class="comparison-table"><thead><tr><th>Anomaly</th><th>Description</th><th>Example</th></tr></thead><tbody><tr><td><strong>Lost Updates</strong></td><td>One saga overwrites changes made by another saga without reading them first.</td><td>Saga A changes an order. Saga B also changes the same order. Saga A&#39;s changes are lost.</td></tr><tr><td><strong>Dirty Reads</strong></td><td>A saga reads data that another saga has written but not yet committed (or will later roll back).</td><td>Saga B reads an order that Saga A created, but Saga A later rolls back and cancels the order.</td></tr><tr><td><strong>Fuzzy / Nonrepeatable Reads</strong></td><td>A saga reads the same data twice and gets different results because another saga modified it in between.</td><td>Saga A reads an order&#39;s total, then reads it again later and the total has changed because Saga B updated it.</td></tr></tbody></table><div class="info-box warning-box"><p><strong>Key problem:</strong> These anomalies can cause incorrect business decisions. For example, a dirty read might cause a saga to approve an order that will be cancelled moments later. You must use countermeasures to reduce or eliminate these risks.</p></div></div><h3 class="subsection-title" id="s4-3-2">Countermeasures for Handling the Lack of Isolation</h3><div class="content-section"><p>There are six countermeasures that reduce or eliminate isolation anomalies. Choose the right one based on the specific anomaly and your business requirements.</p><h4 class="subsubsection-title">1. Semantic Lock</h4><p>Set a flag on the record to indicate it is being processed by a saga. For example, an order might have a status like <code>APPROVAL_PENDING</code> or <code>CANCEL_PENDING</code>. This acts as an application-level lock.</p><p>Other sagas or operations that see the <code>*_PENDING</code> flag know the record is locked. They can either <strong>retry later</strong> (wait for the saga to finish) or <strong>block</strong> until the lock is released.</p><div class="pattern-summary"><h4>Countermeasure: Semantic Lock</h4><div class="ps-row"><span class="ps-label">How</span> <span>Use *_PENDING states as application-level locks on records being modified by a saga.</span></div><div class="ps-row"><span class="ps-label">Handles</span> <span>Lost Updates, Dirty Reads</span></div><div class="ps-row"><span class="ps-label">Trade-off</span> <span>Other operations must handle locked records (retry or block).</span></div></div><h4 class="subsubsection-title">2. Commutative Updates</h4><p>Design your update operations so that they can be executed in any order and still produce the same result. If operations are commutative, the order in which concurrent sagas run does not matter, and lost updates are eliminated.</p><p>For example, instead of &quot;set balance to X,&quot; use &quot;add amount to balance&quot; and &quot;subtract amount from balance.&quot; These operations produce the same final result regardless of order.</p><h4 class="subsubsection-title">3. Pessimistic View</h4><p>Reorder the steps of a saga so that risky updates happen in <strong>retriable transactions</strong> (after the pivot) instead of compensatable transactions (before the pivot). Since retriable transactions are guaranteed to succeed, dirty reads of their intermediate state are less dangerous.</p><p>This reduces the window in which another saga can read inconsistent data.</p><h4 class="subsubsection-title">4. Reread Value</h4><p>Before updating a record, read it again and verify that it has not changed since the saga first read it. If the value has changed, abort the saga and restart it. This is essentially the <strong>Optimistic Offline Lock</strong> pattern.</p><p>This countermeasure prevents lost updates by detecting concurrent modifications.</p><h4 class="subsubsection-title">5. Version File</h4><p>Instead of applying updates directly, record the operations in a log (version file). Then reorder the logged operations so that they become commutative before applying them. This turns noncommutative operations into commutative ones.</p><p>For example, if &quot;authorize credit card&quot; arrives before &quot;create order&quot; due to a concurrent saga, the version file can reorder them into the correct sequence before execution.</p><h4 class="subsubsection-title">6. By Value</h4><p>Dynamically choose the concurrency mechanism based on the <strong>business risk</strong> of each request. Low-risk requests use a saga (with its weaker isolation). High-risk requests use a distributed transaction (with stronger guarantees but lower availability).</p><p>This is a pragmatic approach: most requests are low-risk, so the saga handles them efficiently. Only critical operations pay the cost of stricter consistency.</p><table class="comparison-table"><thead><tr><th>Countermeasure</th><th>Anomaly Addressed</th><th>How It Works</th></tr></thead><tbody><tr><td>Semantic Lock</td><td>Lost Updates, Dirty Reads</td><td>Application-level *_PENDING lock flag</td></tr><tr><td>Commutative Updates</td><td>Lost Updates</td><td>Design operations to be order-independent</td></tr><tr><td>Pessimistic View</td><td>Dirty Reads</td><td>Move risky updates to retriable transactions</td></tr><tr><td>Reread Value</td><td>Lost Updates</td><td>Verify data unchanged before update (optimistic lock)</td></tr><tr><td>Version File</td><td>Fuzzy Reads</td><td>Log and reorder operations before applying</td></tr><tr><td>By Value</td><td>All (selective)</td><td>Choose saga or distributed transaction per request risk</td></tr></tbody></table></div><h2 class="section-title" id="s4-4">4.4 The Design of the Order Service and the Create Order Saga</h2><div class="content-section"><p>This section shows how the Saga pattern is implemented in practice using the Create Order Saga from the FTGO application. It uses the Eventuate Tram Saga framework for orchestration.</p></div><h3 class="subsection-title" id="s4-4-1">The OrderService Class</h3><div class="content-section"><p>The <strong>OrderService</strong> class is the entry point for creating orders. When it receives a &quot;create order&quot; request, it does two things in a single transaction:</p><ol><li>Creates an <strong>Order</strong> entity in the database (in a PENDING state).</li><li>Creates a <strong>CreateOrderSagaState</strong> object that holds the saga&#39;s persistent state.</li></ol><p>It then calls <code>SagaManager.create()</code> to start the saga. The SagaManager takes over and drives the saga through its steps.</p><div class="info-box note-box"><p><strong>Note:</strong> The Order Service acts as both the <strong>orchestrator</strong> (it owns the saga) and a <strong>participant</strong> (it receives commands to approve or reject the order). This dual role is common in practice.</p></div></div><h3 class="subsection-title" id="s4-4-2">The Implementation of the Create Order Saga</h3><div class="content-section"><h4 class="subsubsection-title">CreateOrderSaga — The Saga Definition</h4><p>The <strong>CreateOrderSaga</strong> class is a singleton that defines the saga&#39;s steps. It uses the Eventuate Tram Saga DSL (domain-specific language) to declare each step:</p><ul><li><code>step()</code> — defines a step in the saga</li><li><code>invokeParticipant()</code> — specifies the command to send to a participant</li><li><code>withCompensation()</code> — specifies the compensating command if the saga must roll back</li><li><code>onReply()</code> — handles the participant&#39;s reply</li></ul><p>The saga definition is purely declarative. It describes <em>what</em> to do, not <em>how</em> to do it. The framework handles the execution.</p><h4 class="subsubsection-title">CreateOrderSagaState — The Persistent State</h4><p>The <strong>CreateOrderSagaState</strong> class holds data that the saga needs across steps. It creates command messages for each participant and processes reply messages. The SagaManager persists this state in a <code>SAGA_INSTANCE</code> table so the saga can survive restarts and failures.</p><h4 class="subsubsection-title">Saga Participant Proxy Classes</h4><p>Each participant has a <strong>proxy class</strong> (e.g., <code>KitchenServiceProxy</code>, <code>OrderServiceProxy</code>) that defines the participant&#39;s messaging API:</p><ul><li>The <strong>message channel</strong> to send commands to</li><li>The <strong>command types</strong> the participant accepts</li><li>The <strong>reply types</strong> the participant sends back</li></ul><p>These proxy classes provide a clean, typed interface for the orchestrator to communicate with participants.</p><h4 class="subsubsection-title">SagaManager — The Execution Engine</h4><p>The <strong>SagaManager</strong> is the framework component that drives the saga. It:</p><ol><li>Persists the saga instance in the <code>SAGA_INSTANCE</code> database table.</li><li>Sends the first command message to the first participant.</li><li>Subscribes to reply messages from participants.</li><li>On each reply, advances the state machine to the next state and sends the next command.</li><li>On failure, sends compensating commands in reverse order.</li></ol><div class="pattern-summary"><h4>Implementation Architecture</h4><div class="ps-row"><span class="ps-label">Orchestrator</span> <span>CreateOrderSaga (defines steps) + CreateOrderSagaState (holds data)</span></div><div class="ps-row"><span class="ps-label">Engine</span> <span>SagaManager persists saga state and drives the state machine</span></div><div class="ps-row"><span class="ps-label">Proxies</span> <span>KitchenServiceProxy, OrderServiceProxy — define participant channels and command/reply types</span></div><div class="ps-row"><span class="ps-label">Persistence</span> <span>SAGA_INSTANCE table stores saga state across steps</span></div><div class="ps-row"><span class="ps-label">Framework</span> <span>Eventuate Tram Saga</span></div></div></div><h3 class="subsection-title" id="s4-4-3">The OrderCommandHandlers Class</h3><div class="content-section"><p>The <strong>OrderCommandHandlers</strong> class is an adapter that handles commands sent by sagas <em>to</em> the Order Service. Remember: the Order Service is both the orchestrator and a participant. When the saga sends a command like &quot;approve order&quot; or &quot;reject order,&quot; the OrderCommandHandlers class receives it and calls the appropriate method on the Order entity.</p><p>A <strong>SagaCommandDispatcher</strong> routes incoming command messages to the correct handler method in OrderCommandHandlers. This dispatcher is configured to listen on the Order Service&#39;s command channel.</p><div class="info-box note-box"><p><strong>Pattern:</strong> The separation between the saga definition (CreateOrderSaga), the saga state (CreateOrderSagaState), and the command handlers (OrderCommandHandlers) keeps the code organized. Each class has a single responsibility.</p></div></div><h3 class="subsection-title" id="s4-4-4">The OrderServiceConfiguration Class</h3><div class="content-section"><p>The <strong>OrderServiceConfiguration</strong> class wires everything together. It configures:</p><ul><li>The <strong>CreateOrderSaga</strong> singleton — the saga definition</li><li>The <strong>SagaManager</strong> — the execution engine</li><li>The <strong>OrderCommandHandlers</strong> — the command handlers for when Order Service is a participant</li><li>The <strong>SagaCommandDispatcher</strong> — routes commands to handlers</li><li>The <strong>participant proxy classes</strong> — define messaging APIs for other services</li></ul><p>This configuration class is the glue that connects the orchestrator, the participants, and the messaging infrastructure.</p><div class="info-box key-point-box"><p><strong>Summary of the architecture:</strong> OrderService creates the order and starts the saga. SagaManager drives the state machine, sending commands to participants via proxy classes and processing their replies. OrderCommandHandlers handle commands sent to the Order Service itself. The framework persists all saga state so it survives failures.</p></div></div><section class="takeaways"><h3>Key Takeaways</h3><ul><li>In a microservice architecture, each service has its own database. Cross-service operations cannot use a single ACID transaction.</li><li>Distributed transactions (X/Open XA, 2PC) do not work in modern microservices because many technologies do not support them and they reduce availability.</li><li>The <strong>Saga pattern</strong> maintains consistency through a sequence of local transactions coordinated via asynchronous messaging. On failure, compensating transactions undo completed steps.</li><li>Sagas provide Atomicity, Consistency, and Durability — but <strong>not Isolation</strong>.</li><li>Saga steps are classified as compensatable (before the pivot), pivot (the go/no-go point), or retriable (after the pivot, guaranteed to succeed).</li><li><strong>Choreography</strong> coordinates sagas through events exchanged between participants — simple but hard to understand at scale.</li><li><strong>Orchestration</strong> uses a central orchestrator modeled as a state machine — clearer flow, recommended for most sagas.</li><li>The lack of isolation causes three anomalies: Lost Updates, Dirty Reads, and Fuzzy Reads.</li><li>Six countermeasures address these anomalies: Semantic Lock, Commutative Updates, Pessimistic View, Reread Value, Version File, and By Value.</li><li>In practice, the Eventuate Tram Saga framework provides a DSL for defining sagas, a SagaManager for execution, and participant proxy classes for typed communication.</li><li>A service can be both the saga orchestrator and a saga participant — the Order Service in FTGO plays both roles.</li></ul></section>`,32),e(`div`,p,[r(m,{to:`/sa/microservices/ch3`,class:`prev`},{default:a(()=>[...l[7]||=[n(`← Chapter 3`,-1)]]),_:1}),r(m,{to:`/sa/microservices/ch5`,class:`next`},{default:a(()=>[...l[8]||=[n(`Chapter 5 →`,-1)]]),_:1})])])])}var h=c(l,[[`render`,m]]);export{h as default};